using SchoolEnterprise.Models.Domain; using SchoolEnterprise.Services; namespace SchoolEnterprise.Repositories; public class AttendanceRepository(XmlStorageService storage) : BaseXmlRepository<AttendanceEntry>(storage){ protected override string FileName=>"attendance.xml"; public List<AttendanceEntry> GetByRecord(int recordId)=>GetAll().Where(x=>x.StudentRecordId==recordId).ToList(); public void Upsert(AttendanceEntry i){var a=GetAll();var x=a.FindIndex(t=>t.StudentRecordId==i.StudentRecordId&&t.Date.Date==i.Date.Date);if(x>=0)a[x]=i;else a.Add(i);SaveAll(a);} }
